import os, sys, json, argparse, numpy as np
from collections import deque
from cogniplan_env import ExplorationEnv

def rc(c):
    return (round(c[0],1), round(c[1],1))

class Planner:
    def __init__(self, alpha=1.0, alpha_slope=2.0, vp=0.5, nuw=0.8):
        self.alpha = alpha
        self.alpha_slope = alpha_slope
        self.vp = vp
        self.nuw = nuw
        self.visited = set()
        self.step = 0

    def reset(self):
        self.visited = set()
        self.step = 0

    def select(self, obs):
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        rp = rc(obs['robot_pos'])
        er = obs['explored_rate']
        self.visited.add(rp)
        self.step += 1
        if not neighbors:
            return None

        # Build graph
        graph = {}
        nbc = {}
        for n in nodes:
            c = rc(n['coords'])
            nbc[c] = n
            graph[c] = [rc(nb) for nb in n['neighbors']]

        # BFS from robot
        start = rp
        if start not in graph:
            md = float('inf')
            for c in graph:
                d = (c[0]-rp[0])**2 + (c[1]-rp[1])**2
                if d < md:
                    md = d
                    start = c

        dist = {start: 0}
        pred = {start: None}
        q = deque([start])
        while q:
            cur = q.popleft()
            for nb in graph.get(cur, []):
                if nb not in dist:
                    dist[nb] = dist[cur] + 1
                    pred[nb] = cur
                    q.append(nb)

        # Aggregated utility
        au = {}
        for n in nodes:
            c = rc(n['coords'])
            u = float(n['utility'])
            for nb in graph.get(c, []):
                nn = nbc.get(nb)
                if nn:
                    u += self.nuw * float(nn['utility'])
            au[c] = u

        ea = self.alpha + self.alpha_slope * er

        # Neighbor set
        ns = set()
        nm = {}
        for nb in neighbors:
            nr = rc(nb)
            ns.add(nr)
            if nr not in nm:
                nm[nr] = nb

        # Score neighbors
        def score_set(vp_val):
            best_s = -float('inf')
            best_t = None
            for nr in ns:
                if nr not in dist or dist[nr] == 0:
                    continue
                u = au.get(nr, 0)
                if nr in self.visited:
                    u *= (1.0 - vp_val)
                if u <= 0:
                    continue
                s = u / (dist[nr] ** ea)
                if s > best_s:
                    best_s = s
                    best_t = nr
            return best_t

        bt = score_set(self.vp)
        if bt is None:
            bt = score_set(0.0)

        # Fallback: find best distant node, trace path
        if bt is None:
            best_s = -float('inf')
            best_node = None
            for c, u in au.items():
                if c in self.visited:
                    u *= (1.0 - self.vp)
                if u <= 0 or c not in dist:
                    continue
                s = u / (dist[c] ** ea)
                if s > best_s:
                    best_s = s
                    best_node = c
            if best_node is not None and best_node in pred:
                # Trace back to find first step
                path = []
                cur = best_node
                while cur is not None and cur != start:
                    path.append(cur)
                    cur = pred[cur]
                path.reverse()
                if path:
                    first = path[0]
                    if first in ns:
                        bt = first

        # Pick any unvisited neighbor
        if bt is None:
            for nr in ns:
                if nr not in self.visited:
                    bt = nr
                    break

        # Pick first neighbor
        if bt is None and neighbors:
            bt = rc(neighbors[0])

        if bt is not None:
            return nm.get(bt, bt)
        return None

def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for _ in range(128):
        target = planner.select(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done', False):
            break
    return env.get_metrics()

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    # Load config
    cfg_path = os.path.join(args.checkpoint, 'config.json')
    if os.path.exists(cfg_path):
        with open(cfg_path) as f:
            cfg = json.load(f)
    else:
        cfg = {}

    planner = Planner(
        alpha=cfg.get('alpha', 1.0),
        alpha_slope=cfg.get('alpha_slope', 2.0),
        vp=cfg.get('visited_penalty', 0.5),
        nuw=cfg.get('neighbor_util_weight', 0.8),
    )

    # Load eval config
    with open(os.path.join(args.data_path, 'eval_config.json')) as f:
        eval_cfg = json.load(f)

    episodes = []
    for env_type in eval_cfg.get('env_types', ['room', 'tunnel', 'outdoor']):
        mp = os.path.join(args.data_path, 'maps_eval', env_type)
        if not os.path.isdir(mp):
            mp = os.path.join(args.data_path, env_type)
        if not os.path.isdir(mp):
            continue
        for fn in sorted(os.listdir(mp)):
            if fn.endswith('.png'):
                mpath = os.path.join(mp, fn)
                env = ExplorationEnv(map_path=mpath)
                m = run_episode(env, planner)
                episodes.append({
                    'map_path': f"{env_type}/{fn}",
                    'env_type': env_type,
                    'success': 1 if m['success'] else 0,
                    'travel_distance': round(m['travel_distance'], 4),
                    'explored_rate': round(m['explored_rate'], 4),
                })

    n = len(episodes)
    if n == 0:
        json.dump({'explored_rate': 0, 'travel_distance': 0, 'success_rate': 0, 'per_episode': [], 'per_type': {}, 'total_episodes': 0}, open(args.output, 'w'), indent=2)
        return

    sr = np.mean([e['success'] for e in episodes])
    sd = [e['travel_distance'] for e in episodes if e['success']]
    td = float(np.mean(sd)) if sd else 0.0
    er = float(np.mean([e['explored_rate'] for e in episodes]))

    pt = {}
    for et in set(e['env_type'] for e in episodes):
        te = [e for e in episodes if e['env_type'] == et]
        tsr = float(np.mean([e['success'] for e in te]))
        tsd = [e['travel_distance'] for e in te if e['success']]
        ttd = float(np.mean(tsd)) if tsd else 0.0
        ter = float(np.mean([e['explored_rate'] for e in te]))
        pt[et] = {'explored_rate': ter, 'travel_distance': ttd, 'success_rate': tsr}

    result = {
        'explored_rate': er,
        'travel_distance': td,
        'success_rate': sr,
        'per_episode': episodes,
        'per_type': pt,
        'total_episodes': n,
    }
    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)

if __name__ == '__main__':
    main()
